export async function GET() {
  const sb = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL || '',
    process.env.SUPABASE_SERVICE_ROLE_KEY || '',
    { auth: { autoRefreshToken: false, persistSession: false } }
  )
  let inserted = 0; const errors: string[] = []
  for (let i = 0; i < DATA.length; i += 50) {
    const { error, count } = await sb.from('hasta_kayitlari').insert(DATA.slice(i,i+50), { count: 'exact' })
    if (error) errors.push(error.message.slice(0,100))
    else inserted += count || 50
  }
  const { count } = await sb.from('hasta_kayitlari').select('*', { count: 'exact', head: true })
  return NextResponse.json({ inserted, errors, total: count, part: 2 })
}
